;----------------------------------------------------------------
; BIOS - Terminate a program, and if the error code is non-zero:
;          Display an Error Code on OUT_1
;          Turn on the ERR LED
;
; Location: ROM addr 0x1a90
;
; Input - R0 = Error Code
;----------------------------------------------------------------

.= 0x1a90

os_exit:
   clr r1               ; Error Code = 0 ?
   cmp r0,r1
   jne disp_err
   end                  ; No error - Just stop the program

disp_err:
   mov r0,r1            ; Display the Error Code
   ldi r0,OUT_1
   call os_disp_out
   ldi r0,1             ; Turn the ERR LED on
   ldi r1,ERR
   st r0,[r1]
   end                  ; Stop the program

